ules WHERE course_id=?')->execute([$courseId]); $mo=1; foreach($mods as $mod){$pdo->prepare('INSERT INTO lms_modules (course_id,title,description,sort_order,status) VALUES (?,?,?,?,"Published")')->execute([$courseId,$mod[0],$mod[0].' module with practical examples and applied exercises.',$mo]); $mid=(int)$pdo->lastInsertId(); $lo=1; foreach($mod[1] as $lesson){$content="$lesson is taught in plain language for learners who want practical AI and data skills. In this lesson, you learn the concept, why it matters, and how it can be applied in an African business, school, NGO, farm, public office, or professional team. Focus on the problem first, then the data, then the tool. Good digital transformation is practical, ethical, and measurable."; $assignment="Identify one real situation where $lesson could improve a decision, reduce manual work, or create a better service. Write the data needed, the people involved, and one risk to manage."; $pdo->prepare('INSERT INTO lms_lessons (module_id,title,lesson_type,content,video_url,resource_url,assignment_instructions,estimated_duration,sort_order,status) VALUES (?,?,?,?,?,?,?,?,?,"Published")')->execute([$mid,$lesson,'Text',$content,'https://example.com/video-placeholder','https://example.com/resource-placeholder.pdf',$assignment,'25 minutes',$lo++]);} $mo++;} $pdo->prepare('INSERT INTO lms_quizzes (course_id,title,pass_mark,status) VALUES (?,?,70,"Published")')->execute([$courseId,$title.' Final Quiz']); $qid=(int)$pdo->lastInsertId(); for($i=1;$i<=10;$i++){ $pdo->prepare('INSERT INTO lms_quiz_questions (quiz_id,question,option_a,option_b,option_c,option_d,correct_option,explanation,sort_order) VALUES (?,?,?,?,?,?,?,?,?)')->execute([$qid,"$title question $i: what is the best learning approach?",'Start with the real problem and data','Choose tools before understanding needs','Ignore users and context','Avoid measuring outcomes','A','Mugah DeepTech Academy teaches practical, problem-first AI and data work.',$i]);}}
